const clamp=(n,e,o)=>Math.max(e,Math.min(n,o));function precisionRound(n,e=1){e=Math.pow(10,e);return Math.round(n*e)/e}function precision(n){return((""+n).split(".")[1]||"").length}function decimatedClamp(n,e,o,r){var t;return null==r||r<=0?clamp(n,e,o):(t=precision(r),n=precisionRound(Math.round((n-e)/r)*r,t),o=precisionRound(Math.floor((o-e)/r)*r,t),e+clamp(n,0,o))}function rescale(n,e,o,r={}){return decimatedClamp((n-e[0])/(e[1]-e[0])*(o[1]-o[0])+o[0],o[0],o[1],r.step)}export{clamp,precisionRound,rescale};